(112,'joke_u1_20260402113600','2026-04-02 11:36:07','2026-04-02 16:36:07',2,'{\"object\":\"text_completion\",\"created\":1775129767,\"model\":\"huihui-ai\\/Huihui-Qwen3-8B-abliterated-v2\",\"choices\":[{\"text\":\"\\\"Did you hear about the watch that won the Nobel Prize? It was so precise, it could predict when the owner would stop being late. Unfortunately, it only won for the *first* time\\u2014it kept breaking after that.\\\"\",\"index\":0,\"logprobs\":null,\"finish_reason\":\"length\",\"stop_reason\":null,\"prompt_logprobs\":null}],\"usage\":{\"prompt_tokens\":119,\"completion_tokens\":589,\"total_tokens\":708}}'),
(113,'comvid_u1_52_20260402','2026-04-02 16:37:37','2026-04-02 11:37:37',2,'{\"status\":\"success\",\"webhook_type\":\"success\",\"track_id\":\"comvid_u1_52_20260402\",\"id\":173630622,\"output\":[\"https:\\/\\/pub-3626123a908346a7a8be8d9295f44e26.r2.dev\\/generations\\/59c436db-f3bd-49f6-b196-70febe8c35f5.mp4\"],\"meta\":{\"model_id\":\"ltx-2-3-pro-i2v\",\"prompt\":\"Did you hear about the watch that won the Nobel Prize? It was so precise, it could predict when the owner would stop being late. Unfortunately, it only won for the *first* time\\u2014it kept breaking after that.\",\"resolution\":\"1920x1080\",\"negative_prompt\":\"blurry, low quality, distorted, extra limbs, missing limbs, broken fingers, deformed, glitch, artifacts, unrealistic, low resolution, bad anatomy, duplicate, cropped, watermark, text, logo, jpeg artifacts, noisy, oversaturated, underexposed, overexposed, flicker, unstable motion, motion blur, stretched, mutated, out of frame, bad proportions\",\"webhook\":\"https:\\/\\/app.aistandup.live\\/api\\/aigen\\/saveresponse\",\"generate_audio\":true,\"duration\":\"8\",\"track_id\":\"comvid_u1_52_20260402\",\"init_image\":[\"https:\\/\\/app.aistandup.live\\/public\\/templates\\/social\\/object-as-person.jpg\"]}}'),
(114,'joke_u1_20260402113857','2026-04-02 11:39:03','2026-04-02 16:39:04',2,'{\"object\":\"text_completion\",\"created\":1775129943,\"model\":\"huihui-ai\\/Huihui-Qwen3-8B-abliterated-v2\",\"choices\":[{\"text\":\"Did you know cats are the only animals that will sit on your keyboard and then judge you for using it? Unlike dogs, who are happy to be your best friend, cats are like your ex who never sends a text but still expects you to check their Instagram. They\\u2019ll knock over your plants, steal your food, and then when you\\u2019re upset, they\\u2019ll rub against your legs like they\\u2019re trying to apologize with a paw print. So next time you\\u2019re sad, just remember: your cat\\u2019s love is conditional, but it\\u2019s always on your lap.\",\"index\":0,\"logprobs\":null,\"finish_reason\":\"length\",\"stop_reason\":null,\"prompt_logprobs\":null}],\"usage\":{\"prompt_tokens\":119,\"completion_tokens\":590,\"total_tokens\":709}}'),
(115,'joke_u1_20260402114032','2026-04-02 11:40:38','2026-04-02 16:40:38',2,'{\"object\":\"text_completion\",\"created\":1775130038,\"model\":\"huihui-ai\\/Huihui-Qwen3-8B-abliterated-v2\",\"choices\":[{\"text\":\"You know you\'re a cat person when you start to believe that your furniture is just a temporary base of operations for their global takeover. They\\u2019ve got their own version of the CIA, and their mission is to dismantle your carefully curated living space\\u2014starting with the vase you *vaguely* remember buying for its aesthetic value. By the time you realize your lamp is now a tomb for a dead mouse, you\\u2019re already halfway to accepting that the only way to survive is to join their cause. So when they knock over your prized collection of human-made objects, it\\u2019s not just a vase\\u2014it\\u2019s a declaration of war. And you\\u2019re the collateral damage.\",\"index\":0,\"logprobs\":null,\"finish_reason\":\"length\",\"stop_reason\":null,\"prompt_logprobs\":null}],\"usage\":{\"prompt_tokens\":119,\"completion_tokens\":536,\"total_tokens\":655}}'),
(116,'joke_u1_20260402114908','2026-04-02 11:49:23','2026-04-02 16:49:23',2,'{\"object\":\"text_completion\",\"created\":1775130562,\"model\":\"huihui-ai\\/Huihui-Qwen3-8B-abliterated-v2\",\"choices\":[{\"text\":\"Why did the cat bring a ladder? To see if the ceiling was cat-friendly.\",\"index\":0,\"logprobs\":null,\"finish_reason\":\"length\",\"stop_reason\":null,\"prompt_logprobs\":null}],\"usage\":{\"prompt_tokens\":163,\"completion_tokens\":1447,\"total_tokens\":1610}}'),
(117,'joke_u1_20260402115234','2026-04-02 11:52:41','2026-04-02 16:52:41',2,'{\"object\":\"text_completion\",\"created\":1775130760,\"model\":\"huihui-ai\\/Huihui-Qwen3-8B-abliterated-v2\",\"choices\":[{\"text\":\"\\\"Ever notice how cats treat you like you\'re the gift? You bring home a present, and they\'re like, \'Oh, another one? I\'ve had enough.\' But when they knock over your vase, they get the royal treatment. \'Oh no, the cat did it again! Let\'s blame the vase!\'\\\"\",\"index\":0,\"logprobs\":null,\"finish_reason\":\"length\",\"stop_reason\":null,\"prompt_logprobs\":null}],\"usage\":{\"prompt_tokens\":119,\"completion_tokens\":579,\"total_tokens\":698}}'),
